void test_CB_71_0000()
{
    if (skip_test_CB_71_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x6618);
    WriteRegisterWord(RegisterType::SP, 0x16F8);
    WriteRegisterByte(RegisterType::A, 0x36);
    WriteRegisterByte(RegisterType::B, 0x46);
    WriteRegisterByte(RegisterType::C, 0xA3);
    WriteRegisterByte(RegisterType::D, 0xC9);
    WriteRegisterByte(RegisterType::E, 0xEE);
    WriteRegisterFlag(0x70);
    WriteRegisterByte(RegisterType::H, 0xC8);
    WriteRegisterByte(RegisterType::L, 0xDC);
    mmap.EnableIME();
    WriteRegisterByte(RegisterType::IE, 0x00);
    WriteMemory(0x6619, 0x71);
    WriteMemory(0x6618, 0xCB);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 8);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0x36);
    CheckRegisterByte(RegisterType::B, 0x46);
    CheckRegisterByte(RegisterType::C, 0xA3);
    CheckRegisterByte(RegisterType::D, 0xC9);
    CheckRegisterByte(RegisterType::E, 0xEE);
    CheckRegisterFlag(0xB0);
    CheckRegisterByte(RegisterType::H, 0xC8);
    CheckRegisterByte(RegisterType::L, 0xDC);
    CheckRegisterWord(RegisterType::PC, 0x661A);
    CheckRegisterWord(RegisterType::SP, 0x16F8);
    TEST_ASSERT(mmap.IMEEnabled());
    CheckMemory(0x6618, 0xCB);
    CheckMemory(0x6619, 0x71);
}

